sql:
SELECT receptacle_id, receptacle_type, receptacle_capacity
FROM public_receptacles
WHERE receptacle_condition = 'Damaged' AND receptacle_capacity = '20 gallons';

SELECT route_name, service_frequency
FROM collection_routes
WHERE service_type = 'Residential';

SELECT receptacle_type
FROM public_receptacles
WHERE receptacle_condition = 'Damaged';

SELECT participation_status
FROM household_participation
WHERE participation_status = 'Active';

SELECT route_name
FROM collection_routes
ORDER BY route_name ASC;

SELECT COUNT(household_id) AS active_recycling_households
FROM household_participation
WHERE recycling_participation = 1 AND participation_status = 'Active';

external_knowledge:
- 'Active' in participation_status refers to households currently participating in waste management programs; 
- composting_participation = 1 and recycling_participation = 1 indicate that the household participates in both composting and recycling programs; 
- public_receptacles are receptacles available to the public for waste disposal in each section of the municipality.
